css:
@page {
  size: A4; margin: 15mm 16mm 22mm 16mm;
  @bottom-left { content: "Beispiel Handels GmbH · Marktplatz 1 · 10115 Berlin \A Amtsgericht Charlottenburg · HRB 123456 \A Geschäftsführer: Max Beispiel"; font-size: 6.5pt; line-height: 1.45; color: #8a8a8a; white-space: pre-line; vertical-align: top; padding-top: 4mm; }
  @bottom-center { content: "Seite " counter(page) " von " counter(pages); font-size: 6.5pt; color: #8a8a8a; white-space: nowrap; vertical-align: top; padding-top: 4mm; }
  @bottom-right { content: "USt-IdNr. DE123456789 · St.-Nr. 13/456/78901 \A IBAN DE89 3704 0044 0532 0130 00 · BIC COBADEFFXXX"; font-size: 6.5pt; line-height: 1.45; color: #8a8a8a; white-space: pre-line; text-align: right; vertical-align: top; padding-top: 4mm; }
}

body { color: #122019; font-family: 'Helvetica', 'Arial', sans-serif; }
.num { font-variant-numeric: tabular-nums; }
.doc-header { display: block; margin: 0 0 3mm; }

/* Top bar */
.sh-top { display: flex; align-items: center; justify-content: space-between; }
.sh-brand { display: flex; align-items: center; gap: 3mm; }
.sh-mark { height: 10mm; width: 10mm; display: block; }
.sh-brandname { font-size: 12pt; font-weight: 700; letter-spacing: -0.01em; }
.sh-badge { font-size: 8pt; font-weight: 700; letter-spacing: 0.06em; text-transform: uppercase; color: #ffffff; background: #008060; border-radius: 999px; padding: 1.4mm 4mm; }

/* Hero */
.sh-hero { margin: 5mm 0 6mm; }
.sh-hero__eyebrow { font-size: 8pt; letter-spacing: 0.14em; text-transform: uppercase; color: #008060; font-weight: 700; margin-bottom: 1.5mm; }
.sh-hero__title { font-size: 20pt; font-weight: 800; letter-spacing: -0.025em; line-height: 1.08; margin: 0 0 2.5mm; }
.sh-hero__sub { color: #5a6b62; font-size: 9.5pt; max-width: 150mm; line-height: 1.45; }

/* Timeline */
.sh-timeline { display: flex; justify-content: space-between; margin: 0 0 8mm; }
.sh-step { flex: 1 1 0; text-align: center; position: relative; }
.sh-step::before { content: ""; position: absolute; top: 4.5mm; left: -50%; width: 100%; height: 1.2mm; background: #d7e6df; z-index: 0; }
.sh-step:first-child::before { display: none; }
.sh-step--done::before, .sh-step--current::before { background: #2bb783; }
.sh-step__dot { position: relative; z-index: 1; width: 9mm; height: 9mm; border-radius: 50%; margin: 0 auto 2mm; background: #eef4f1; border: 1.4mm solid #d7e6df; color: #fff; font-size: 10pt; line-height: 6.2mm; font-weight: 700; }
.sh-step--done .sh-step__dot { background: #008060; border-color: #008060; }
.sh-step--current .sh-step__dot { background: #fff; border-color: #008060; }
.sh-step__label { font-size: 9pt; font-weight: 700; }
.sh-step--pending .sh-step__label { color: #9aa6a0; }
.sh-step__date { font-size: 8pt; color: #9aa6a0; margin-top: 0.5mm; }

/* Section headings */
.sh-h2 { font-size: 9pt; letter-spacing: 0.12em; text-transform: uppercase; color: #008060; font-weight: 700; margin: 0 0 3mm; }

/* Product rows (hairline list — robust height) */
.sh-items { border-top: 1px solid #e5efe9; margin-bottom: 8mm; }
.sh-card { display: flex; align-items: center; gap: 4mm; padding: 3mm 1mm; border-bottom: 1px solid #e5efe9; }
.sh-thumb { flex: 0 0 11mm; height: 11mm; border-radius: 2.2mm; display: flex; align-items: center; justify-content: center; font-weight: 800; font-size: 10pt; color: #1f5c47; }
.sh-card__body { flex: 1 1 auto; min-width: 0; }
.sh-card__name { font-weight: 700; font-size: 10.5pt; }
.sh-card__variant { color: #5a6b62; font-size: 9pt; margin-top: 0.3mm; }
.sh-card__sku { color: #9aa6a0; font-size: 8pt; margin-top: 0.4mm; }
.sh-card__qty { flex: 0 0 auto; color: #5a6b62; font-size: 10pt; font-variant-numeric: tabular-nums; }
.sh-card__price { flex: 0 0 28mm; text-align: right; font-weight: 800; font-size: 11pt; font-variant-numeric: tabular-nums; }

/* Footer split */
.sh-foot { display: flex; gap: 8mm; align-items: flex-start; }
.sh-ship { flex: 1 1 0; }
.sh-ship__addr { line-height: 1.45; font-size: 9.5pt; margin-bottom: 3.5mm; }
.sh-track { background: #f6faf8; border: 1px solid #e5efe9; border-radius: 3mm; padding: 3mm 4mm; }
.sh-track__row { display: flex; justify-content: space-between; padding: 1mm 0; font-size: 9.5pt; }
.sh-track__row span { color: #5a6b62; }
.sh-qr { display: flex; align-items: center; gap: 3mm; margin-top: 3.5mm; font-size: 9pt; color: #5a6b62; }
.sh-qr svg { width: 17mm; height: 17mm; }

.sh-summary { flex: 0 0 68mm; background: #103d30; color: #eafaf4; border-radius: 4mm; padding: 5mm 5.5mm; }
.sh-summary .sh-h2 { color: #7fe3c3; }
.sh-srow { display: flex; justify-content: space-between; padding: 1.4mm 0; font-size: 10pt; color: #cfe9df; }
.sh-srow--disc span:last-child { color: #7fe3c3; }
.sh-srow--total { margin-top: 2mm; padding-top: 2.5mm; border-top: 1px solid #2e5a4b; font-size: 14pt; font-weight: 800; color: #ffffff; }
.sh-srow__note { margin-top: 2.5mm; font-size: 8pt; color: #8fb3a6; }
